transformScript:
let chapters = [];
for chapter in response.entries {
    let pages = [];
    for page in chapter.pages {
        pages.push(#{
            url: "https://images.reader.example/" + page.path,
            width: page.width,
            height: page.height
        });
    }
    chapters.push(#{
        number: chapter.number,
        volume: chapter.volume,
        pages: pages
    });
}
#{
    title: response.title,
    language: response.language,
    chapters: chapters
}
